class OrderedStream {
    constructor(n) {
        this.stream = new Array(n + 1).fill(null);
        this.n = n;
        this.ptr = 1;
    }
    insert(idKey, value) {
        this.stream[idKey] = value;
        const res = [];
        while (this.ptr <= this.n && this.stream[this.ptr] !== null) {
            res.push(this.stream[this.ptr]);
            this.ptr += 1;
        }
        return res;
    }
}
